import * as React from 'react';

interface LinkItem {
  href: string;
  label: string;
  social: string;
  icon: React.ReactNode;
}

const socialColors: Record<string, string> = {
  linkedin: '#0274b3',
  github: '#24262a',
  facebook: '#1877f2',
  twitter: '#000000',
};

const defaultLinks: LinkItem[] = [
  {
    href: 'https://linkedin.com/',
    label: 'LinkedIn',
    social: 'linkedin',
    icon: (
      <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" viewBox="0 0 16 16">
        <path d="M0 1.146C0 .513.526 0 1.175 0h13.65C15.474 0 16 .513 16 1.146v13.708c0 .633-.526 1.146-1.175 1.146H1.175C.526 16 0 15.487 0 14.854zm4.943 12.248V6.169H2.542v7.225zm-1.2-8.212c.837 0 1.358-.554 1.358-1.248-.015-.709-.52-1.248-1.342-1.248S2.4 3.226 2.4 3.934c0 .694.521 1.248 1.327 1.248zm4.908 8.212V9.359c0-.216.016-.432.08-.586.173-.431.568-.878 1.232-.878.869 0 1.216.662 1.216 1.634v3.865h2.401V9.25c0-2.22-1.184-3.252-2.764-3.252-1.274 0-1.845.7-2.165 1.193v.025h-.016l.016-.025V6.169h-2.4c.03.678 0 7.225 0 7.225z" />
      </svg>
    ),
  },
  {
    href: 'https://www.github.com/',
    label: 'GitHub',
    social: 'github',
    icon: (
      <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" viewBox="0 0 16 16">
        <path d="M8 0C3.58 0 0 3.58 0 8c0 3.54 2.29 6.53 5.47 7.59.4.07.55-.17.55-.38 0-.19-.01-.82-.01-1.49-2.01.37-2.53-.49-2.69-.94-.09-.23-.48-.94-.82-1.13-.28-.15-.68-.52-.01-.53.63-.01 1.08.58 1.23.82.72 1.21 1.87.87 2.33.66.07-.52.28-.87.51-1.07-1.78-.2-3.64-.89-3.64-3.95 0-.87.31-1.59.82-2.15-.08-.2-.36-1.02.08-2.12 0 0 .67-.21 2.2.82.64-.18 1.32-.27 2-.27s1.36.09 2 .27c1.53-1.04 2.2-.82 2.2-.82.44 1.1.16 1.92.08 2.12.51.56.82 1.27.82 2.15 0 3.07-1.87 3.75-3.65 3.95.29.25.54.73.54 1.48 0 1.07-.01 1.93-.01 2.2 0 .21.15.46.55.38A8.01 8.01 0 0 0 16 8c0-4.42-3.58-8-8-8" />
      </svg>
    ),
  },
  {
    href: 'https://facebook.com/',
    label: 'Facebook',
    social: 'facebook',
    icon: (
      <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" viewBox="0 0 16 16">
        <path d="M16 8.049c0-4.446-3.582-8.05-8-8.05C3.58 0-.002 3.603-.002 8.05c0 4.017 2.926 7.347 6.75 7.951v-5.625h-2.03V8.05H6.75V6.275c0-2.017 1.195-3.131 3.022-3.131.876 0 1.791.157 1.791.157v1.98h-1.009c-.993 0-1.303.621-1.303 1.258v1.51h2.218l-.354 2.326H9.25V16c3.824-.604 6.75-3.934 6.75-7.951z" />
      </svg>
    ),
  },
  {
    href: 'https://x.com/',
    label: 'X',
    social: 'twitter',
    icon: (
      <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" viewBox="0 0 16 16">
        <path d="M12.6.75h2.454l-5.36 6.142L16 15.25h-4.937l-3.867-5.07-4.425 5.07H.316l5.733-6.57L0 .75h5.063l3.495 4.633L12.601.75Zm-.86 13.028h1.36L4.323 2.145H2.865z" />
      </svg>
    ),
  },
];

interface LinksPanelProps {
  links?: LinkItem[];
  className?: string;
}

const LinksPanel: React.FC<LinksPanelProps> = ({ links = defaultLinks, className = '' }) => {
  return (
    <ul className={`flex list-none items-center justify-center p-0 ${className}`}>
      {links.map((link) => {
        const color = socialColors[link.social] || '#333';
        const isGradient = color.startsWith('linear-gradient');

        return (
          <li key={link.social} className="group relative mx-4">
            <a
              href={link.href}
              aria-label={link.label}
              target="_blank"
              rel="noopener noreferrer"
              className="relative flex h-[72px] w-[72px] items-center justify-center overflow-hidden rounded-full bg-white text-[#4d4d4d] transition-all duration-300 ease-in-out hover:text-white hover:shadow-lg"
            >
              <div
                className="absolute bottom-0 left-0 h-0 w-full transition-all duration-300 ease-in-out group-hover:h-full"
                style={isGradient ? { background: color } : { backgroundColor: color }}
              />
              <span className="relative z-10 flex h-[44px] w-[44px] items-center justify-center [&>svg]:h-[32px] [&>svg]:w-[32px]">
                {link.icon}
              </span>
            </a>
            <div
              className="pointer-events-none absolute top-[80px] left-1/2 -translate-x-1/2 whitespace-nowrap rounded-md px-2.5 py-1.5 text-sm text-white opacity-0 invisible transition-all duration-300 group-hover:top-[90px] group-hover:opacity-100 group-hover:visible"
              style={isGradient ? { background: color } : { backgroundColor: color }}
            >
              {link.label}
            </div>
          </li>
        );
      })}
    </ul>
  );
};

export default LinksPanel;
